function getStatus() {
  const roll = Math.random() * 100;
  if(roll < 50) {
    return 'Resolved';
  }

  if(roll < 80) {
    return 'Open';
  }

  if (roll < 90) {
    return "Failed";
  }

  return 'HandedOverToOperator';
}

function createRequestId() {
  let idPrefix = '';
  const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
  const charactersLength = characters.length;
  for (let i = 0; i < 5; i++) {
    idPrefix += characters.charAt(Math.floor(Math.random() * charactersLength));
  }

  // Generate a random number between 100 and 999
  const randomNum = Math.floor(Math.random() * 9000) + 1000;

  // Concatenate static characters with the random number
  const shortId = `${idPrefix}${randomNum}`;

  return shortId;
}
